// velite.config.ts
import { defineConfig, s } from "velite";
import { z as z2 } from "zod";

// ../../../src/lib/skills-schema.ts
import { z } from "zod";
var SKILL_CATEGORIES = ["frontend", "backend", "infra", "testing"];
var skillSchema = z.strictObject({
  slug: z.string().min(1).regex(/^[a-z0-9]+(?:-[a-z0-9]+)*$/, "slug must be kebab-case"),
  name: z.string().min(1),
  category: z.enum(SKILL_CATEGORIES),
  /** Sort order within a category (ascending). */
  order: z.number().int(),
  /** Slugs of projects that demonstrate this skill (deep-linked evidence). */
  projectSlugs: z.array(z.string().min(1)).optional()
});

// velite.config.ts
var velite_config_default = defineConfig({
  root: "content",
  strict: true,
  output: {
    data: ".velite",
    assets: "static",
    base: "/static/",
    name: "[name]-[hash:6].[ext]",
    clean: true
  },
  collections: {
    skills: {
      name: "Skill",
      pattern: "skills/**/*.mdx",
      schema: s.object({
        slug: s.string(),
        name: s.string(),
        category: s.string(),
        order: s.number(),
        projectSlugs: s.array(s.string()).optional(),
        body: s.mdx()
      }).transform(({ body, ...frontmatter }, ctx) => {
        const result = skillSchema.safeParse(frontmatter);
        if (!result.success) {
          for (const issue of result.error.issues) {
            ctx.addIssue({
              code: "custom",
              message: issue.message,
              path: issue.path.map(String)
            });
          }
          return z2.NEVER;
        }
        return { ...result.data, body };
      })
    }
  }
});
export {
  velite_config_default as default
};
